+    local procedure UpdateServiceOrderStatus()
+    var
+        ServiceItemLineLocal: Record "Service Item Line";
+        RepairStatusLocal: Record "Repair Status";
+        RepairStatusLocal2: Record "Repair Status";
+        ServiceHeaderLocal: Record "Service Header";
+        ServiceHeaderLocal2: Record "Service Header";
+        RepairStatusPriorityLocal: Integer;
+        UseLineNoLocal: Integer;
+    begin
+        if "Repair Status Code" = '' then
+            exit;
+
+        RepairStatusLocal.Get("Repair Status Code");
+        RepairStatusPriorityLocal := RepairStatusLocal.Priority;
+        UseLineNoLocal := "Line No.";
+
+        ServiceItemLineLocal.Reset();
+        ServiceItemLineLocal.SetRange("Document Type", "Document Type");
+        ServiceItemLineLocal.SetRange("Document No.", "Document No.");
+        ServiceItemLineLocal.SetFilter("Line No.", '<>%1', "Line No.");
+        ServiceItemLineLocal.SetFilter("Repair Status Code", '<>%1', '');
+        if ServiceItemLineLocal.FindSet() then
