+                RepairStatusLocal2.Get(ServiceItemLineLocal."Repair Status Code");
+                if RepairStatusLocal2.Priority < RepairStatusPriorityLocal then begin
+                    RepairStatusPriorityLocal := RepairStatusLocal2.Priority;
+                    UseLineNoLocal := ServiceItemLineLocal."Line No.";
+                end;
+            until ServiceItemLineLocal.Next() = 0;
+
+        if "Line No." <> UseLineNoLocal then begin
+            ServiceItemLineLocal.Get("Document Type", "Document No.", UseLineNoLocal);
+            RepairStatusLocal.Get(ServiceItemLineLocal."Repair Status Code");
+        end else
+            RepairStatusLocal.Get("Repair Status Code");
+
+        ServiceHeaderLocal.Get("Document Type", "Document No.");
+        if ServiceHeaderLocal.Status <> RepairStatusLocal."Service Order Status" then begin
+            ServiceHeaderLocal2 := ServiceHeaderLocal;
+            ServiceHeaderLocal.SetValidatingFromLines(true);
+            ServiceHeaderLocal.Validate(Status, RepairStatusLocal."Service Order Status");
+            if not (ServiceHeaderLocal.Status = ServiceHeaderLocal.Status::Finished) then begin
+                ServiceHeaderLocal."Finishing Date" := 0D;
+                ServiceHeaderLocal."Finishing Time" := 0T;
+                ServiceHeaderLocal."Service Time (Hours)" := 0;
+            end;
+            ServiceHeaderLocal.UpdateServiceOrderChangeLog(ServiceHeaderLocal2);
+            ServiceHeaderLocal.Modify();
+        end;
+    end;
